metric.command:
          python -c "
import json
r = json.load(open('reports/exhaustive_all_configs_report.json', encoding='utf-8'))
sc = r.get('summaries_compact', {})
llm_off = [v for k,v in sc.items() if v['quality'] <= 10]
if not llm_off: exit()
dims = {}
for v in llm_off:
    for d,s in v['dimensions'].items():
        dims.setdefault(d, []).append(s)
print('LLM OFF dimensions:')
for d in ['relevance','clarity','interactive','structure','personalization','encouragement']:
    vals = dims.get(d, [0])
    print(f'  {d}: {sum(vals)/len(vals):.2f}/4')
"
